// Check the quest panel state at runtime
var questPanel = UnityEngine.Object.FindObjectOfType<TowerDefense.UI.QuestPanel>();
if (questPanel != null)
{
    UnityEngine.Debug.Log($"QuestPanel found, active: {questPanel.gameObject.activeInHierarchy}");

    // Check _questPanel field
    var questPanelType = questPanel.GetType();
    var itemContainerField = questPanelType.GetField("_itemContainer", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    var questItemPrefabField = questPanelType.GetField("_questItemPrefab", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    var spawnedItemsField = questPanelType.GetField("_spawnedItems", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

    var container = itemContainerField.GetValue(questPanel) as UnityEngine.Transform;
    var prefab = questItemPrefabField.GetValue(questPanel) as UnityEngine.GameObject;
    var spawned = spawnedItemsField.GetValue(questPanel) as System.Collections.Generic.List<UnityEngine.GameObject>;

    UnityEngine.Debug.Log($"ItemContainer: {(container != null ? container.name + " childCount=" + container.childCount : "NULL")}");
    UnityEngine.Debug.Log($"QuestItemPrefab: {(prefab != null ? prefab.name + " active=" + prefab.activeSelf : "NULL")}");
    UnityEngine.Debug.Log($"SpawnedItems count: {(spawned != null ? spawned.Count.ToString() : "NULL")}");

    // Check the Frame
    var frame = questPanel.transform.Find("Frame");
    if (frame != null)
    {
        UnityEngine.Debug.Log($"Frame active: {frame.gameObject.activeInHierarchy}");
        var sidebar = frame.Find("ContentArea/Sidebar");
        if (sidebar != null)
        {
            UnityEngine.Debug.Log($"Sidebar active: {sidebar.gameObject.activeInHierarchy}, childCount: {sidebar.childCount}");
            for (int i = 0; i < sidebar.childCount; i++)
            {
                var child = sidebar.GetChild(i);
                UnityEngine.Debug.Log($"  Tab[{i}]: {child.name}, active: {child.gameObject.activeInHierarchy}, size: {child.GetComponent<UnityEngine.RectTransform>().rect}");
