// Properly fix the ContentArea layout
var questPanel = UnityEngine.GameObject.Find("Canvas/QuestPanel");
var contentArea = questPanel.transform.Find("Frame/ContentArea");
var contentAreaHLG = contentArea.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();

// Reset: don't force expand - let LayoutElements control it
contentAreaHLG.childForceExpandWidth = false;
contentAreaHLG.childControlWidth = true;

// Sidebar: fixed width 130
var sidebar = contentArea.Find("Sidebar");
var sidebarLE = sidebar.GetComponent<UnityEngine.UI.LayoutElement>();
sidebarLE.minWidth = 130;
sidebarLE.preferredWidth = 130;
sidebarLE.flexibleWidth = 0;

// RightArea: fill remaining space
var rightArea = contentArea.Find("RightArea");
var rightAreaLE = rightArea.GetComponent<UnityEngine.UI.LayoutElement>();
rightAreaLE.minWidth = 100;
rightAreaLE.preferredWidth = -1;  // let it be calculated
rightAreaLE.flexibleWidth = 1;

UnityEngine.Debug.Log($"ContentArea HLG: forceExpandW={contentAreaHLG.childForceExpandWidth}, controlW={contentAreaHLG.childControlWidth}");
UnityEngine.Debug.Log($"Sidebar LE: minW={sidebarLE.minWidth}, prefW={sidebarLE.preferredWidth}, flexW={sidebarLE.flexibleWidth}");
UnityEngine.Debug.Log($"RightArea LE: minW={rightAreaLE.minWidth}, prefW={rightAreaLE.preferredWidth}, flexW={rightAreaLE.flexibleWidth}");

// Force rebuild layout
UnityEngine.UI.LayoutRebuilder.ForceRebuildLayoutImmediate(contentArea.GetComponent<UnityEngine.RectTransform>());
UnityEngine.Debug.Log($"Sidebar width after rebuild: {sidebar.GetComponent<UnityEngine.RectTransform>().rect.width}");
UnityEngine.Debug.Log($"RightArea width after rebuild: {rightArea.GetComponent<UnityEngine.RectTransform>().rect.width}");

