// Fix QuestItemPrefab's HorizontalLayoutGroup
var prefab = UnityEngine.GameObject.Find("QuestItemPrefab");
if (prefab == null)
{
    UnityEngine.Debug.LogError("QuestItemPrefab not found in scene root!");
}
else
{
    var hlg = prefab.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();
    UnityEngine.Debug.Log($"Before: childControlWidth={hlg.childControlWidth}, childForceExpandWidth={hlg.childForceExpandWidth}");

    // Enable child control width so LayoutElement sizes take effect
    hlg.childControlWidth = true;
    hlg.childForceExpandWidth = false;

    // Make TextBlock flexible to fill available space
    var textBlock = prefab.transform.Find("TextBlock");
    var textBlockLE = textBlock.GetComponent<UnityEngine.UI.LayoutElement>();
    UnityEngine.Debug.Log($"TextBlock LE before: prefW={textBlockLE.preferredWidth}, flexW={textBlockLE.flexibleWidth}");
    textBlockLE.flexibleWidth = 1;
    textBlockLE.preferredWidth = -1; // let it calculate naturally

    // Force rebuild
    UnityEngine.UI.LayoutRebuilder.ForceRebuildLayoutImmediate(prefab.GetComponent<UnityEngine.RectTransform>());

    // Check results
    for (int i = 0; i < prefab.transform.childCount; i++)
    {
        var child = prefab.transform.GetChild(i);
        var rect = child.GetComponent<UnityEngine.RectTransform>();
        UnityEngine.Debug.Log($"  {child.name}: rect={rect.rect}");
    }
}

// Find QuestItemPrefab even if inactive - search by instanceID from earlier (34066)
// Or use FindObjectsOfType with includeInactive
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.Transform>();
UnityEngine.GameObject prefab = null;
foreach (var t in allTransforms)
{
    if (t.name == "QuestItemPrefab" && t.parent == null && t.gameObject.scene.isLoaded)
    {
        prefab = t.gameObject;
        break;
    }
}

if (prefab != null)
{
    UnityEngine.Debug.Log($"Found QuestItemPrefab, activeSelf={prefab.activeSelf}");

    var hlg = prefab.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();
    UnityEngine.Debug.Log($"Before: childControlWidth={hlg.childControlWidth}, childForceExpandWidth={hlg.childForceExpandWidth}");

    hlg.childControlWidth = true;
    hlg.childForceExpandWidth = false;

    // Make TextBlock flexible to fill available space
    var textBlock = prefab.transform.Find("TextBlock");
    var textBlockLE = textBlock.GetComponent<UnityEngine.UI.LayoutElement>();
    UnityEngine.Debug.Log($"TextBlock LE before: prefW={textBlockLE.preferredWidth}, flexW={textBlockLE.flexibleWidth}");
    textBlockLE.flexibleWidth = 1;
    textBlockLE.preferredWidth = -1;

    // Force rebuild
    prefab.SetActive(true);
    UnityEngine.UI.LayoutRebuilder.ForceRebuildLayoutImmediate(prefab.GetComponent<UnityEngine.RectTransform>());
    prefab.SetActive(false);

    UnityEngine.Debug.Log("QuestItemPrefab layout fixed!");
}
else
{
    UnityEngine.Debug.LogError("QuestItemPrefab not found!");
}

