// Fix all internal layout groups of QuestItemPrefab
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.Transform>();
UnityEngine.GameObject prefab = null;
foreach (var t in allTransforms)
{
    if (t.name == "QuestItemPrefab" && t.parent == null && t.gameObject.scene.isLoaded)
    {
        prefab = t.gameObject;
        break;
    }
}

if (prefab != null)
{
    // 1. TextBlock VLG: enable childControlHeight
    var textBlock = prefab.transform.Find("TextBlock");
    var textBlockVLG = textBlock.GetComponent<UnityEngine.UI.VerticalLayoutGroup>();
    textBlockVLG.childControlHeight = true;
    textBlockVLG.childForceExpandHeight = false;
    UnityEngine.Debug.Log("Fixed TextBlock VLG: childControlHeight=True");

    // 2. ProgressArea VLG: enable childControlHeight and fix width
    var progressArea = prefab.transform.Find("ProgressArea");
    var progressAreaVLG = progressArea.GetComponent<UnityEngine.UI.VerticalLayoutGroup>();
    progressAreaVLG.childControlHeight = true;
    progressAreaVLG.childControlWidth = true;
    progressAreaVLG.childForceExpandWidth = false;
    progressAreaVLG.childForceExpandHeight = false;
    var progressAreaLE = progressArea.GetComponent<UnityEngine.UI.LayoutElement>();
    progressAreaLE.flexibleWidth = 0;
    UnityEngine.Debug.Log("Fixed ProgressArea VLG and LayoutElement");

    // 3. RewardArea HLG: enable child control
    var rewardArea = prefab.transform.Find("RewardArea");
    var rewardAreaHLG = rewardArea.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();
    rewardAreaHLG.childControlWidth = true;
    rewardAreaHLG.childControlHeight = true;
    rewardAreaHLG.childForceExpandWidth = false;
    rewardAreaHLG.childForceExpandHeight = false;
    UnityEngine.Debug.Log("Fixed RewardArea HLG");

    // 4. Also fix the parent HLG to ensure ProgressArea stays at preferred width
    var parentHLG = prefab.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();
    parentHLG.childControlWidth = true;
    parentHLG.childForceExpandWidth = false;
    UnityEngine.Debug.Log("Parent HLG: childControlWidth=True, childForceExpandWidth=False");

    // Force rebuild
    prefab.SetActive(true);
    UnityEngine.UI.LayoutRebuilder.ForceRebuildLayoutImmediate(prefab.GetComponent<UnityEngine.RectTransform>());

    // Check results
    for (int i = 0; i < prefab.transform.childCount; i++)
    {
        var sub = prefab.transform.GetChild(i);
        var rect = sub.GetComponent<UnityEngine.RectTransform>();
        UnityEngine.Debug.Log($"  {sub.name}: width={rect.rect.width}, height={rect.rect.height}");
    }

    prefab.SetActive(false);
    UnityEngine.Debug.Log("QuestItemPrefab internal layouts fixed!");
}

