args.script:
// Fix all tab Content HLGs and add ContentSizeFitters to Icon/Label
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.Transform>();
UnityEngine.GameObject questPanelObj = null;
foreach (var t in allTransforms)
{
    if (t.name == "QuestPanel" && t.parent != null && t.parent.name == "Canvas" && t.gameObject.scene.isLoaded)
    {
        questPanelObj = t.gameObject;
        break;
    }
}

if (questPanelObj == null) { UnityEngine.Debug.LogError("QuestPanel not found"); return; }

var sidebar = questPanelObj.transform.Find("Frame/ContentArea/Sidebar");
if (sidebar == null) { UnityEngine.Debug.LogError("Sidebar not found"); return; }

for (int i = 0; i < sidebar.childCount; i++)
{
    var tab = sidebar.GetChild(i);
    var content = tab.Find("Content");
    if (content == null) continue;

    // Fix Content HLG: enable child control so children get sized
    var hlg = content.GetComponent<UnityEngine.UI.HorizontalLayoutGroup>();
    if (hlg != null)
    {
        hlg.childControlWidth = true;
        hlg.childControlHeight = true;
        hlg.childForceExpandWidth = false;
        hlg.childForceExpandHeight = false;
        UnityEngine.Debug.Log($"Fixed {tab.name}/Content HLG");
    }

    // Add ContentSizeFitter to Icon and Label so they report their preferred size
    for (int j = 0; j < content.childCount; j++)
    {
        var child = content.GetChild(j);
        var csf = child.GetComponent<UnityEngine.UI.ContentSizeFitter>();
        if (csf == null)
        {
            csf = child.gameObject.AddComponent<UnityEngine.UI.ContentSizeFitter>();
        }
        csf.horizontalFit = UnityEngine.UI.ContentSizeFitter.FitMode.PreferredSize;
        csf.verticalFit = UnityEngine.UI.ContentSizeFitter.FitMode.PreferredSize;
        UnityEngine.Debug.Log($"  Added/fixed CSF on {child.name}");
    }
}

UnityEngine.Debug.Log("Tab layout fixes applied!");

