var all = UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.GameObject>();
foreach (var go in all)
{
    if (go.name == "QuestPanel" && go.transform.parent != null && go.transform.parent.name == "Canvas")
    {
        go.SetActive(true);
        var qp = go.GetComponent<TowerDefense.UI.QuestPanel>();
        if (qp != null) qp.OpenQuest();
        break;
    }
}

